                            transport.map((item) => (
                                <Card key={item.id} className="overflow-hidden hover:border-primary/50 transition-colors cursor-pointer" onClick={() => { onSelect(item); setOpen(false); }}>
                                    <CardContent className="p-4 flex items-center justify-between">
