                                            <div className="flex items-center gap-2 mb-1">
                                                <Badge variant="outline" className="capitalize text-[10px] px-1.5 py-0 h-4">
                                                    {item.type === 'flight' ? <Plane className="h-2.5 w-2.5 mr-1" /> : <Bus className="h-2.5 w-2.5 mr-1" />}
