import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { authService, User } from '../services/auth';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  login: (email: string, password: string) => Promise<{ mfaRequired: boolean; email?: string; user?: User }>;
  adminLogin: (email: string, password: string) => Promise<{ mfaRequired: boolean; email?: string; user?: User }>;
  verifyMFA: (email: string, code: string) => Promise<User>;
  register: (email: string, password: string, fullName: string, phone?: string) => Promise<void>;
  logout: () => void;
  updateProfile: (fullName?: string, phone?: string, bio?: string, avatarUrl?: string) => Promise<void>;
  toggleMFA: (enabled: boolean) => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Check if user is already logged in on mount
  useEffect(() => {
    const initAuth = async () => {
      try {
        if (authService.isAuthenticated()) {
          const profile = await authService.getProfile();
          setUser(profile);
        }
      } catch (error) {
        console.error('Failed to load user profile:', error);
        authService.clearToken();
      } finally {
        setIsLoading(false);
      }
    };

    initAuth();
  }, []);

  const login = async (email: string, password: string) => {
    setIsLoading(true);
    try {
      const { user: userData, mfaRequired } = await authService.login(email, password);
      if (!mfaRequired && userData) {
        setUser(userData);
      }
      return { mfaRequired: !!mfaRequired, email, user: userData };
    } finally {
      setIsLoading(false);
    }
  };

  const adminLogin = async (email: string, password: string) => {
    setIsLoading(true);
    try {
      const { user: userData, mfaRequired } = await authService.adminLogin(email, password);
      if (!mfaRequired && userData) {
        setUser(userData);
      }
      return { mfaRequired: !!mfaRequired, email, user: userData };
    } finally {
      setIsLoading(false);
    }
  };

  const verifyMFA = async (email: string, code: string) => {
    setIsLoading(true);
    try {
      const { user: userData } = await authService.verifyMFA(email, code);
      if (userData) {
        setUser(userData);
      }
      return userData!;
    } finally {
      setIsLoading(false);
    }
  };

  const register = async (email: string, password: string, fullName: string, phone?: string) => {
    setIsLoading(true);
    try {
      const { user: userData, token } = await authService.register(email, password, fullName, phone);
      authService.setToken(token);
      setUser(userData);
    } finally {
      setIsLoading(false);
    }
  };

  const logout = () => {
    authService.clearToken();
    setUser(null);
  };

  const updateProfile = async (fullName?: string, phone?: string, bio?: string, avatarUrl?: string) => {
    try {
      const updatedUser = await authService.updateProfile(fullName, phone, bio, avatarUrl);
      setUser(updatedUser);
    } catch (error) {
      throw error;
    }
  };

  const toggleMFA = async (enabled: boolean) => {
    try {
      await authService.toggleMFA(enabled);
      // Update user in context
      if (user) {
        setUser({ ...user, two_factor_enabled: enabled });
      }
    } catch (error) {
      throw error;
    }
  };

  const value: AuthContextType = {
    user,
    isLoading,
    isAuthenticated: !!user,
    login,
    adminLogin,
    verifyMFA,
    register,
    logout,
    updateProfile,
    toggleMFA,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
}

import { useState, useEffect } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { ArrowLeft, CreditCard, Phone, Shield, CheckCircle, Lock } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import Layout from "@/components/layout/Layout";
import { useAuth } from "@/context/AuthContext";
import { bookingsService } from "@/services/bookings";
import { toast } from "sonner";
import { Navigate } from "react-router-dom";

type PaymentMethod = "mtn" | "vodafone" | "airteltigo" | "card";

interface BookingData {
  type: "hotel" | "guide" | "activity" | "transport";
  id: string;
  name: string;
  roomId?: string;
  roomType?: string;
  checkInDate?: string;
  checkOutDate?: string;
  date?: string;
  time?: string;
  nights?: number;
  guests: number;
  price: number;
  totalPrice: number;
}

const paymentMethods = [
  { id: "mtn" as const, name: "MTN Mobile Money", icon: "📱", color: "border-warning bg-warning/5", description: "Pay with your MTN MoMo wallet" },
  { id: "vodafone" as const, name: "Vodafone Cash", icon: "📱", color: "border-destructive/50 bg-destructive/5", description: "Pay with Vodafone Cash" },
  { id: "airteltigo" as const, name: "AirtelTigo Money", icon: "📱", color: "border-info bg-info/5", description: "Pay with AirtelTigo Money" },
  { id: "card" as const, name: "Visa / Mastercard", icon: "💳", color: "border-primary bg-primary/5", description: "Pay with debit or credit card" },
];

const Checkout = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { isAuthenticated, isLoading } = useAuth();

  const bookingData = location.state as BookingData | undefined;
  const [selectedMethod, setSelectedMethod] = useState<PaymentMethod | null>(null);
  const [step, setStep] = useState<"method" | "details" | "confirm">("method");
  const [isProcessing, setIsProcessing] = useState(false);
  const [userTrips, setUserTrips] = useState<any[]>([]);
  const [selectedTripId, setSelectedTripId] = useState<string | "none">("none");

  useEffect(() => {
    if (isAuthenticated) {
      loadTrips();
    }
  }, [isAuthenticated]);

  const loadTrips = async () => {
    try {
      const { tripsService } = await import("@/services/trips");
      const trips = await tripsService.getUserTrips();
      setUserTrips(trips.filter(t => t.status === "planning" || t.status === "ongoing"));
    } catch (error) {
      console.error("Failed to load trips", error);
    }
  };

  if (isLoading) {
    return (
      <Layout>
        <div className="container py-20 text-center">
          <p className="text-muted-foreground">Loading...</p>
        </div>
      </Layout>
    );
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" />;
  }

  if (!bookingData) {
    return (
      <Layout>
        <div className="container max-w-4xl py-8">
          <h1 className="mb-2 font-display text-3xl font-bold">Invalid Booking</h1>
          <p className="mb-4 text-muted-foreground">No booking information found.</p>
          <Button onClick={() => navigate("/hotels")}>Back to Hotels</Button>
        </div>
      </Layout>
    );
  }

  const handlePayment = async () => {
    if (!selectedMethod) {
      toast.error("Please select a payment method");
      return;
    }

    setIsProcessing(true);
    try {
      const booking = await bookingsService.createBooking({
        bookingType: bookingData.type,
        referenceId: bookingData.id,
        roomId: bookingData.roomId,
        checkInDate: bookingData.checkInDate || bookingData.date,
        checkOutDate: bookingData.checkOutDate,
        totalPrice: bookingData.totalPrice,
        numberOfGuests: bookingData.guests,
        tripId: selectedTripId === "none" ? undefined : selectedTripId,
      });

      toast.success("Booking completed successfully!");
      navigate("/dashboard/bookings");
    } catch (error: any) {
      toast.error(error.message || "Failed to process booking");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <Layout>
      <div className="container max-w-4xl py-8">
        <button onClick={() => navigate(-1)} className="mb-6 inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-primary">
          <ArrowLeft className="h-4 w-4" /> Back
        </button>

        <h1 className="mb-2 font-display text-3xl font-bold">Checkout</h1>
        <p className="mb-8 text-muted-foreground">Complete your booking payment securely</p>

        {/* Progress */}
        <div className="mb-8 flex items-center gap-2">
          {["Payment Method", "Details", "Confirm"].map((label, i) => {
            const stepIndex = i;
            const currentIndex = step === "method" ? 0 : step === "details" ? 1 : 2;
            return (
              <div key={label} className="flex items-center gap-2">
                <div className={`flex h-8 w-8 items-center justify-center rounded-full text-sm font-semibold ${stepIndex <= currentIndex ? "bg-primary text-primary-foreground" : "bg-muted text-muted-foreground"
                  }`}>
                  {stepIndex < currentIndex ? <CheckCircle className="h-4 w-4" /> : stepIndex + 1}
                </div>
                <span className={`text-sm font-medium ${stepIndex <= currentIndex ? "text-foreground" : "text-muted-foreground"}`}>{label}</span>
                {i < 2 && <div className={`h-px w-8 sm:w-16 ${stepIndex < currentIndex ? "bg-primary" : "bg-border"}`} />}
              </div>
            );
          })}
        </div>

        <div className="grid gap-8 lg:grid-cols-3">
          <div className="lg:col-span-2">
            {step === "method" && (
              <div className="space-y-4">
                <h2 className="font-display text-xl font-semibold">Select Payment Method</h2>

                <div className="space-y-3">
                  {paymentMethods.map((m) => (
                    <button
                      key={m.id}
                      onClick={() => setSelectedMethod(m.id)}
                      className={`flex w-full items-center gap-4 rounded-xl border-2 p-4 text-left transition-all ${selectedMethod === m.id ? m.color + " ring-2 ring-primary/20" : "border-border hover:border-primary/30"
                        }`}
                    >
                      <span className="text-2xl">{m.icon}</span>
                      <div className="flex-1">
                        <p className="font-semibold">{m.name}</p>
                        <p className="text-sm text-muted-foreground">{m.description}</p>
                      </div>
                      <div className={`h-5 w-5 rounded-full border-2 ${selectedMethod === m.id ? "border-primary bg-primary" : "border-border"
                        }`}>
                        {selectedMethod === m.id && <CheckCircle className="h-full w-full text-primary-foreground" />}
                      </div>
                    </button>
                  ))}
                </div>

                <Button size="lg" className="w-full" disabled={!selectedMethod} onClick={() => setStep("details")}>
                  Continue
                </Button>
              </div>
            )}

            {step === "details" && selectedMethod && (
              <div className="space-y-4">
                <h2 className="font-display text-xl font-semibold">
                  {selectedMethod === "card" ? "Card Details" : "Mobile Money Details"}
                </h2>

                {selectedMethod === "card" ? (
                  <div className="space-y-4 rounded-xl border border-border bg-card p-6">
                    <div>
                      <label className="mb-1 block text-sm font-medium">Cardholder Name</label>
                      <Input placeholder="Full name on card" />
                    </div>
                    <div>
                      <label className="mb-1 block text-sm font-medium">Card Number</label>
                      <div className="relative">
                        <CreditCard className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                        <Input placeholder="1234 5678 9012 3456" className="pl-10" />
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="mb-1 block text-sm font-medium">Expiry Date</label>
                        <Input placeholder="MM/YY" />
                      </div>
                      <div>
                        <label className="mb-1 block text-sm font-medium">CVV</label>
                        <Input placeholder="123" type="password" />
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="space-y-4 rounded-xl border border-border bg-card p-6">
                    <div>
                      <label className="mb-1 block text-sm font-medium">
                        {selectedMethod === "mtn" ? "MTN" : selectedMethod === "vodafone" ? "Vodafone" : "AirtelTigo"} Phone Number
                      </label>
                      <div className="relative">
                        <Phone className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                        <Input placeholder="+233 XX XXX XXXX" className="pl-10" />
                      </div>
                    </div>
                    <div>
                      <label className="mb-1 block text-sm font-medium">Account Name</label>
                      <Input placeholder="Name on mobile money account" />
                    </div>
                    <p className="rounded-lg bg-muted p-3 text-sm text-muted-foreground">
                      You will receive a payment prompt on your phone. Please approve the transaction to complete your booking.
                    </p>
                  </div>
                )}

                <div className="flex gap-3">
                  <Button variant="outline" size="lg" onClick={() => setStep("method")}>Back</Button>
                  <Button size="lg" className="flex-1" onClick={() => setStep("confirm")}>Review & Pay</Button>
                </div>
              </div>
            )}

            {step === "confirm" && (
              <div className="space-y-4">
                <h2 className="font-display text-xl font-semibold">Confirm Payment</h2>
                <div className="rounded-xl border border-border bg-card p-6">
                  <div className="mb-4 flex items-center gap-3">
                    <CheckCircle className="h-5 w-5 text-success" />
                    <p className="font-medium">Payment method: {paymentMethods.find((m) => m.id === selectedMethod)?.name}</p>
                  </div>
                  <p className="mb-6 text-sm text-muted-foreground">
                    By clicking "Pay Now", you agree to our terms of service and privacy policy. Your payment will be processed securely.
                  </p>
                  <Button size="lg" className="w-full gap-2" onClick={handlePayment} disabled={isProcessing}>
                    <Lock className="h-4 w-4" /> {isProcessing ? "Processing..." : `Pay GH₵${Number(bookingData.totalPrice).toFixed(2)}`}
                  </Button>
                  <div className="mt-4 flex items-center justify-center gap-2 text-xs text-muted-foreground">
                    <Shield className="h-3 w-3" />
                    <span>Secured by Paystack & Hubtel</span>
                  </div>
                </div>
                <Button variant="outline" size="lg" onClick={() => setStep("details")}>Back</Button>
              </div>
            )}
          </div>

          {/* Order Summary */}
          <div>
            <div className="sticky top-20 rounded-2xl border border-border bg-card p-6">
              <h3 className="mb-4 font-display text-lg font-semibold">Booking Summary</h3>
              <div className="mb-4 space-y-3">
                <div className="rounded-lg bg-muted p-3">
                  <p className="font-medium">{bookingData.name}</p>
                  {bookingData.roomType && (
                    <p className="text-sm font-semibold text-emerald-600">{bookingData.roomType}</p>
                  )}
                  <p className="text-sm text-muted-foreground">
                    {bookingData.checkInDate
                      ? `${new Date(bookingData.checkInDate).toLocaleDateString()} - ${new Date(bookingData.checkOutDate!).toLocaleDateString()} • ${bookingData.nights} nights`
                      : `${new Date(bookingData.date!).toLocaleDateString()} ${bookingData.time ? `at ${bookingData.time}` : ""}`}
                  </p>
                  <p className="text-sm text-muted-foreground">{bookingData.guests} guest{bookingData.guests > 1 ? "s" : ""}</p>
                </div>

                {userTrips.length > 0 && (
                  <div className="space-y-2">
                    <label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Link to Trip (Optional)</label>
                    <select
                      value={selectedTripId}
                      onChange={(e) => setSelectedTripId(e.target.value)}
                      className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20"
                    >
                      <option value="none">No trip (standalone booking)</option>
                      {userTrips.map((trip) => (
                        <option key={trip.id} value={trip.id}>
                          {trip.destination} ({new Date(trip.start_date).toLocaleDateString()})
                        </option>
                      ))}
                    </select>
                  </div>
                )}
              </div>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">
                    GH₵{Number(bookingData.price).toFixed(2)} {bookingData.nights ? `× ${bookingData.nights} nights` : "per person"}
                  </span>
                  <span className="font-medium">
                    GH₵{(Number(bookingData.price) * (bookingData.nights || 1) * (bookingData.type === 'activity' ? bookingData.guests : 1)).toFixed(2)}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Service fee</span>
                  <span className="font-medium">GH₵{(Number(bookingData.totalPrice) * 0.04).toFixed(2)}</span>
                </div>
                <div className="mt-2 flex justify-between border-t border-border pt-2 text-base font-bold">
                  <span>Total</span><span className="text-primary">GH₵{Number(bookingData.totalPrice).toFixed(2)}</span>
                </div>
              </div>
              <div className="mt-4 flex flex-wrap justify-center gap-2">
                <Badge variant="outline" className="text-xs">MTN MoMo</Badge>
                <Badge variant="outline" className="text-xs">Vodafone Cash</Badge>
                <Badge variant="outline" className="text-xs">Visa/MC</Badge>
              </div>
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default Checkout;

import { useState, useEffect } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { hotelsService, Hotel, HotelRoom } from "@/services/hotels";
import { toast } from "sonner";
import Layout from "@/components/layout/Layout";
import {
  ArrowLeft, Star, MapPin, Wifi, UtensilsCrossed, Dumbbell,
  ParkingCircle, Loader, Calendar, Users, CheckCircle2,
  ChevronRight, Info, ShieldCheck, Heart, Share2,
  ChevronLeft
} from "lucide-react";

const amenityIcons: { [key: string]: React.ReactNode } = {
  wifi: <Wifi className="w-5 h-5 text-emerald-500" />,
  restaurant: <UtensilsCrossed className="w-5 h-5 text-emerald-500" />,
  gym: <Dumbbell className="w-5 h-5 text-emerald-500" />,
  parking: <ParkingCircle className="w-5 h-5 text-emerald-500" />,
  "swimming pool": <span className="text-xl">🏊</span>,
  spa: <span className="text-xl">🧖</span>,
  ac: <span className="text-xl">❄️</span>,
};

export default function HotelDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const [hotel, setHotel] = useState<Hotel | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [checkInDate, setCheckInDate] = useState("");
  const [checkOutDate, setCheckOutDate] = useState("");
  const [guests, setGuests] = useState("1");
  const [selectedRoom, setSelectedRoom] = useState<HotelRoom | null>(null);
  const [activeImage, setActiveImage] = useState(0);

  useEffect(() => {
    if (id) {
      loadHotel();
    }
  }, [id]);

  const loadHotel = async () => {
    try {
      setIsLoading(true);
      const data = await hotelsService.getHotelById(id!);
      setHotel(data);
    } catch (error: any) {
      toast.error("Failed to load hotel details");
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleBooking = (e: React.FormEvent) => {
    e.preventDefault();

    if (!checkInDate || !checkOutDate) {
      toast.error("Please select check-in and check-out dates");
      return;
    }

    if (new Date(checkInDate) >= new Date(checkOutDate)) {
      toast.error("Check-out date must be after check-in date");
      return;
    }

    if (!selectedRoom && hotel?.rooms && hotel.rooms.length > 0) {
      toast.error("Please select a room type");
      const element = document.getElementById("rooms-section");
      element?.scrollIntoView({ behavior: "smooth" });
      return;
    }

    const nights = Math.ceil(
      (new Date(checkOutDate).getTime() - new Date(checkInDate).getTime()) /
      (1000 * 60 * 60 * 24)
    );

    const priceToUse = selectedRoom ? selectedRoom.price_per_night : hotel!.price_per_night;
    const totalPrice = priceToUse * nights * parseInt(guests);

    navigate("/checkout", {
      state: {
        type: 'hotel',
        id: hotel!.id,
        name: hotel!.name,
        roomId: selectedRoom?.id,
        roomType: selectedRoom?.room_type,
        checkInDate,
        checkOutDate,
        nights,
        guests: parseInt(guests),
        price: priceToUse,
        totalPrice,
      },
    });
  };

  if (isLoading) {
    return (
      <Layout>
        <div className="container py-32 flex flex-col items-center justify-center">
          <div className="relative">
            <div className="h-16 w-16 animate-spin rounded-full border-4 border-emerald-500 border-t-transparent" />
            <div className="absolute inset-0 flex items-center justify-center">
              <Loader className="h-6 w-6 text-emerald-500 animate-pulse" />
            </div>
          </div>
          <p className="mt-4 text-muted-foreground font-medium animate-pulse">Designing your stay...</p>
        </div>
      </Layout>
    );
  }

  if (!hotel) {
    return (
      <Layout>
        <div className="container py-20 text-center">
          <div className="bg-muted w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6">
            <Info className="w-10 h-10 text-muted-foreground" />
          </div>
          <h1 className="text-3xl font-bold mb-2">Hotel Not Found</h1>
          <p className="text-muted-foreground mb-8 text-lg">The destination you're seeking seems to have moved or doesn't exist.</p>
          <Button onClick={() => navigate("/hotels")} size="lg" className="rounded-full px-8">Return to Hotels</Button>
        </div>
      </Layout>
    );
  }

  const amenities = hotel.amenities ? hotel.amenities.split(",").map(a => a.trim()) : [];
  const displayImages = hotel.images && hotel.images.length > 0 ? hotel.images : [hotel.image_url || "https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800"];

  return (
    <Layout>
      <div className="bg-muted/30 pb-20">
        {/* Breadcrumb & Quick Actions */}
        <div className="container py-6">
          <div className="flex items-center justify-between mb-6">
            <button
              onClick={() => navigate("/hotels")}
              className="flex items-center gap-2 text-sm font-medium text-muted-foreground hover:text-emerald-700 transition-colors"
            >
              <ArrowLeft className="w-4 h-4" />
              Back to Stays
            </button>
            <div className="flex items-center gap-3">
              <Button variant="outline" size="icon" className="rounded-full shadow-sm hover:bg-rose-50 hover:text-rose-600 transition-all active:scale-95">
                <Heart className="w-4 h-4" />
              </Button>
              <Button variant="outline" size="icon" className="rounded-full shadow-sm hover:bg-emerald-50 hover:text-emerald-600 transition-all active:scale-95">
                <Share2 className="w-4 h-4" />
              </Button>
            </div>
          </div>

          {/* New Image Gallery Layout */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-10 h-[500px]">
            <div className="md:col-span-3 h-full relative group overflow-hidden rounded-3xl shadow-xl">
              <img
                src={displayImages[activeImage]}
                alt={hotel.name}
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent pointer-events-none" />
              <div className="absolute bottom-6 left-8 flex items-end gap-6 text-white pointer-events-none">
                <div className="bg-white/10 backdrop-blur-md rounded-2xl p-4 border border-white/20">
                  <h1 className="text-4xl font-extrabold tracking-tight mb-2">{hotel.name}</h1>
                  <div className="flex items-center gap-2 text-white/90">
                    <MapPin className="h-4 w-4 text-emerald-400" />
                    <span className="font-medium">{hotel.location}, {hotel.region}</span>
                  </div>
                </div>
              </div>
              <div className="absolute inset-y-0 left-4 flex items-center opacity-0 group-hover:opacity-100 transition-all">
                <Button
                  variant="secondary" size="icon" className="rounded-full"
                  onClick={() => setActiveImage(prev => (prev === 0 ? displayImages.length - 1 : prev - 1))}
                >
                  <ChevronLeft className="h-6 w-6" />
                </Button>
              </div>
              <div className="absolute inset-y-0 right-4 flex items-center opacity-0 group-hover:opacity-100 transition-all">
                <Button
                  variant="secondary" size="icon" className="rounded-full"
                  onClick={() => setActiveImage(prev => (prev === displayImages.length - 1 ? 0 : prev + 1))}
                >
                  <ChevronRight className="h-6 w-6" />
                </Button>
              </div>
            </div>
            <div className="hidden md:flex flex-col gap-4">
              {displayImages.slice(0, 3).map((img, idx) => (
                <div
                  key={idx}
                  className={`flex-1 rounded-2xl overflow-hidden cursor-pointer border-4 transition-all ${activeImage === idx ? 'border-emerald-500 ring-2 ring-emerald-500/20 shadow-lg scale-95' : 'border-transparent hover:scale-[1.02] shadow-sm'}`}
                  onClick={() => setActiveImage(idx)}
                >
                  <img src={img} alt={`${hotel.name} ${idx}`} className="w-full h-full object-cover" />
                </div>
              ))}
            </div>
          </div>

          <div className="grid lg:grid-cols-3 gap-10">
            {/* Main Details */}
            <div className="lg:col-span-2 space-y-10">
              {/* Stats & Brief */}
              <div className="flex flex-wrap items-center gap-8 py-6 rounded-3xl bg-white p-8 shadow-sm border border-border/50">
                <div className="space-y-1">
                  <p className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Rating</p>
                  <div className="flex items-center gap-2">
                    <div className="flex items-center bg-yellow-400 text-white px-2 py-0.5 rounded-lg text-sm font-bold">
                      <Star className="w-4 h-4 fill-current mr-1" />
                      {Number(hotel.rating).toFixed(1)}
                    </div>
                    <span className="text-sm font-medium text-muted-foreground">Excellent • {hotel.reviewCount || 0} reviews</span>
                  </div>
                </div>
                <div className="w-px h-10 bg-border hidden md:block" />
                <div className="space-y-1">
                  <p className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Location</p>
                  <p className="font-bold flex items-center gap-1.5"><MapPin className="h-4 w-4 text-emerald-500" /> {hotel.location}</p>
                </div>
                <div className="w-px h-10 bg-border hidden md:block" />
                <div className="space-y-1">
                  <p className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Starting Price</p>
                  <p className="font-bold text-emerald-600 text-xl">GH₵ {Number(hotel.price_per_night).toLocaleString()}</p>
                </div>
              </div>

              {/* Description */}
              <section className="space-y-4">
                <h3 className="text-2xl font-bold tracking-tight">Experience Luxury</h3>
                <p className="text-muted-foreground leading-relaxed text-lg">
                  {hotel.description || "Indulge in an unforgettable stay where luxury meets comfort. Our hotel offers premium service, breathtaking views, and modern amenities designed to exceed your expectations."}
                </p>
                <div className="flex flex-wrap gap-2 pt-4">
                  {amenities.map(a => (
                    <Badge key={a} variant="secondary" className="px-4 py-1.5 rounded-full bg-emerald-50 text-emerald-700 border-emerald-100 hover:bg-emerald-100 transition-all font-medium whitespace-nowrap">
                      {a}
                    </Badge>
                  ))}
                </div>
              </section>

              {/* Room Selection */}
              <section id="rooms-section" className="space-y-6 pt-6">
                <div className="flex items-center justify-between">
                  <h3 className="text-2xl font-bold tracking-tight">Choose Your Sanctuary</h3>
                  <Badge className="bg-emerald-500/10 text-emerald-600 hover:bg-emerald-500/10 border-emerald-500/20">Best Rates Guaranteed</Badge>
                </div>
                <div className="grid gap-4">
                  {hotel.rooms && hotel.rooms.length > 0 ? (
                    hotel.rooms.map((room) => (
                      <Card
                        key={room.id}
                        className={`transition-all duration-300 overflow-hidden group cursor-pointer border-2 ${selectedRoom?.id === room.id ? 'border-emerald-500 bg-emerald-50/10 ring-4 ring-emerald-500/5' : 'hover:border-emerald-200'}`}
                        onClick={() => setSelectedRoom(room)}
                      >
                        <div className="flex flex-col md:flex-row">
                          <div className="md:w-1/3 bg-muted relative overflow-hidden h-48 md:h-auto">
                            <img
                              src={room.images?.[0] || "https://images.unsplash.com/photo-1590490360182-c33d57733427?w=400"}
                              alt={room.room_type}
                              className="w-full h-full object-cover transition-transform group-hover:scale-105"
                            />
                            {room.available_count < 5 && (
                              <Badge className="absolute top-3 left-3 bg-rose-500 border-0">Only {room.available_count} left!</Badge>
                            )}
                          </div>
                          <div className="flex-1 p-6 space-y-4">
                            <div className="flex items-start justify-between gap-4">
                              <div>
                                <h4 className="text-xl font-bold mb-1">{room.room_type}</h4>
                                <div className="flex items-center gap-2 text-sm text-muted-foreground font-medium">
                                  <Users className="h-4 w-4" /> Sleeps up to {room.capacity} adults
                                </div>
                              </div>
                              <div className="text-right">
                                <div className="text-2xl font-black text-emerald-600">GH₵ {room.price_per_night}</div>
                                <div className="text-xs text-muted-foreground font-bold uppercase tracking-wider">Per Night</div>
                              </div>
                            </div>

                            <div className="flex flex-wrap gap-2 text-xs">
                              {room.amenities ? room.amenities.split(',').map(a => (
                                <span key={a} className="flex items-center gap-1 bg-muted px-2 py-1 rounded-md text-muted-foreground font-medium">{a.trim()}</span>
                              )) : (
                                <>
                                  <span className="flex items-center gap-1 bg-muted px-2 py-1 rounded-md text-muted-foreground font-medium">En-suite Bath</span>
                                  <span className="flex items-center gap-1 bg-muted px-2 py-1 rounded-md text-muted-foreground font-medium">Room Service</span>
                                  <span className="flex items-center gap-1 bg-muted px-2 py-1 rounded-md text-muted-foreground font-medium">Lake View</span>
                                </>
                              )}
                            </div>

                            <div className="flex items-center gap-2">
                              <Button
                                className={`rounded-full px-6 transition-all ${selectedRoom?.id === room.id ? 'bg-emerald-600' : 'bg-primary'}`}
                                onClick={(e) => { e.stopPropagation(); setSelectedRoom(room); }}
                              >
                                {selectedRoom?.id === room.id ? <CheckCircle2 className="h-4 w-4 mr-2" /> : null}
                                {selectedRoom?.id === room.id ? "Selected" : "Select Room"}
                              </Button>
                              {selectedRoom?.id === room.id && <span className="text-emerald-600 text-sm font-bold flex items-center gap-1 animate-in fade-in slide-in-from-left-2"><ShieldCheck className="h-4 w-4" /> Reserve this now</span>}
                            </div>
                          </div>
                        </div>
                      </Card>
                    ))
                  ) : (
                    <div className="bg-white rounded-3xl p-10 text-center border shadow-sm">
                      <Loader className="w-10 h-10 text-emerald-500 mx-auto mb-4 opacity-20" />
                      <h4 className="text-lg font-bold">Standard Room Available</h4>
                      <p className="text-muted-foreground text-sm max-w-xs mx-auto">Specific room types aren't listed, please use our standard booking.</p>
                      <Button variant="secondary" className="mt-6 rounded-full px-8" onClick={() => setSelectedRoom(null)}>Reset Selection</Button>
                    </div>
                  )}
                </div>
              </section>

              {/* Reviews Section Placeholder */}
              <section className="pt-10 space-y-6">
                <div className="flex items-center justify-between">
                  <h3 className="text-2xl font-bold tracking-tight">Guest Reviews</h3>
                  <Button variant="outline" className="rounded-full gap-2">Write a Review</Button>
                </div>
                <div className="bg-white p-8 rounded-3xl border shadow-sm">
                  <div className="flex flex-col md:flex-row gap-8 items-center mb-10">
                    <div className="text-center md:text-left">
                      <div className="text-5xl font-black text-emerald-600 mb-2">{Number(hotel.rating).toFixed(1)}</div>
                      <div className="flex items-center justify-center md:justify-start gap-1 mb-2">
                        {[1, 2, 3, 4, 5].map(i => <Star key={i} className={`h-4 w-4 ${i <= Math.floor(Number(hotel.rating)) ? 'fill-yellow-400 text-yellow-400' : 'text-muted'}`} />)}
                      </div>
                      <p className="text-sm text-muted-foreground font-medium">Based on {hotel.reviewCount || 42} verified stays</p>
                    </div>
                    <div className="flex-1 space-y-3 w-full max-w-xs md:max-w-none">
                      {[
                        { label: 'Excellent', count: 85, color: 'bg-emerald-500' },
                        { label: 'Good', count: 12, color: 'bg-teal-400' },
                        { label: 'Average', count: 3, color: 'bg-yellow-400' }
                      ].map(row => (
                        <div key={row.label} className="flex items-center gap-4">
                          <span className="text-xs font-semibold w-24 text-muted-foreground">{row.label}</span>
                          <div className="flex-1 h-2 bg-muted rounded-full overflow-hidden">
                            <div className={`h-full ${row.color}`} style={{ width: `${row.count}%` }} />
                          </div>
                          <span className="text-xs font-bold text-muted-foreground w-8">{row.count}%</span>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="space-y-6 divide-y">
                    {[
                      { name: 'Kweku A.', date: 'Dec 12, 2023', rating: 5, comment: 'Absolutely stunning property. The staff went above and beyond to make our anniversary special.' },
                      { name: 'Ama M.', date: 'Oct 28, 2023', rating: 4, comment: 'Great location near the beach. The breakfast buffet was incredible with lots of local options.' }
                    ].map((rev, i) => (
                      <div key={i} className="pt-6 first:pt-0">
                        <div className="flex items-center justify-between mb-3">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-full bg-emerald-100 flex items-center justify-center text-emerald-700 font-bold">{rev.name[0]}</div>
                            <div>
                              <p className="font-bold text-sm">{rev.name}</p>
                              <p className="text-xs text-muted-foreground">{rev.date}</p>
                            </div>
                          </div>
                          <div className="flex gap-0.5">
                            {[1, 2, 3, 4, 5].map(k => <Star key={k} className={`h-3 w-3 ${k <= rev.rating ? 'fill-yellow-400 text-yellow-400' : 'text-muted'}`} />)}
                          </div>
                        </div>
                        <p className="text-sm text-muted-foreground leading-relaxed">{rev.comment}</p>
                      </div>
                    ))}
                  </div>
                </div>
              </section>
            </div>

            {/* Sticky Sidebar Booking */}
            <div className="relative">
              <aside className="sticky top-24 space-y-6">
                <Card className="rounded-[2.5rem] shadow-2xl border-0 overflow-hidden ring-1 ring-border/50">
                  <div className="bg-emerald-600 p-8 text-white relative">
                    <div className="absolute top-0 right-0 p-4 opacity-20"><Calendar className="h-20 w-20" /></div>
                    <CardHeader className="p-0 mb-4">
                      <CardTitle className="text-2xl font-bold flex items-center gap-2">Book Your Sanctuary</CardTitle>
                      <CardDescription className="text-emerald-100 font-medium opacity-90">Secure the best rate for {hotel.name}</CardDescription>
                    </CardHeader>
                  </div>
                  <CardContent className="p-8 space-y-6 bg-white">
                    <form onSubmit={handleBooking} className="space-y-6">
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                          <label className="text-xs font-bold uppercase tracking-widest text-muted-foreground">Check-in</label>
                          <Input
                            type="date"
                            value={checkInDate}
                            onChange={(e) => setCheckInDate(e.target.value)}
                            required
                            className="rounded-2xl border-muted bg-muted/20 focus-visible:ring-emerald-500 h-12"
                          />
                        </div>
                        <div className="space-y-2">
                          <label className="text-xs font-bold uppercase tracking-widest text-muted-foreground">Check-out</label>
                          <Input
                            type="date"
                            value={checkOutDate}
                            onChange={(e) => setCheckOutDate(e.target.value)}
                            required
                            className="rounded-2xl border-muted bg-muted/20 focus-visible:ring-emerald-500 h-12"
                          />
                        </div>
                      </div>

                      <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-widest text-muted-foreground">Guests</label>
                        <div className="relative">
                          <Users className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                          <Input
                            type="number"
                            min="1"
                            max="10"
                            value={guests}
                            onChange={(e) => setGuests(e.target.value)}
                            required
                            className="rounded-2xl border-muted bg-muted/20 focus-visible:ring-emerald-500 pl-11 h-12"
                          />
                        </div>
                      </div>

                      {selectedRoom && (
                        <div className="p-4 rounded-xl bg-emerald-50 border border-emerald-100 animate-in zoom-in-95">
                          <div className="text-xs font-bold text-emerald-700 uppercase mb-1">Type Selected</div>
                          <div className="font-bold text-sm text-emerald-900">{selectedRoom.room_type}</div>
                          <div className="text-xs text-emerald-600 mt-1">GH₵ {selectedRoom.price_per_night} / night</div>
                        </div>
                      )}

                      {checkInDate && checkOutDate && (
                        <div className="p-6 rounded-2xl bg-muted/30 space-y-3">
                          <div className="flex justify-between text-sm">
                            <span className="text-muted-foreground">Price × {Math.ceil((new Date(checkOutDate).getTime() - new Date(checkInDate).getTime()) / (1000 * 60 * 60 * 24))} nights</span>
                            <span className="font-bold">GH₵ {(selectedRoom?.price_per_night || hotel.price_per_night) * Math.ceil((new Date(checkOutDate).getTime() - new Date(checkInDate).getTime()) / (1000 * 60 * 60 * 24))}</span>
                          </div>
                          <div className="flex justify-between text-sm">
                            <span className="text-muted-foreground">Service Fee</span>
                            <span className="font-bold">GH₵ 0.00</span>
                          </div>
                          <div className="h-px bg-border my-2" />
                          <div className="flex justify-between items-end">
                            <p className="text-sm font-bold">Estimated Total</p>
                            <div className="text-right">
                              <p className="text-2xl font-black text-emerald-600 leading-none">
                                GH₵ {(
                                  (selectedRoom?.price_per_night || hotel.price_per_night) *
                                  Math.ceil(
                                    (new Date(checkOutDate).getTime() -
                                      new Date(checkInDate).getTime()) /
                                    (1000 * 60 * 60 * 24)
                                  ) *
                                  parseInt(guests)
                                ).toLocaleString()}
                              </p>
                              <p className="text-[10px] text-muted-foreground mt-1 uppercase font-bold tracking-widest">including taxes</p>
                            </div>
                          </div>
                        </div>
                      )}

                      <Button type="submit" size="lg" className="w-full rounded-2xl bg-emerald-600 hover:bg-emerald-700 h-14 text-lg font-bold shadow-emerald-200/50 shadow-xl transition-all active:scale-95 group">
                        Confirm & Pay
                        <ChevronRight className="h-5 w-5 ml-2 group-hover:translate-x-1 transition-transform" />
                      </Button>
                      <p className="text-[10px] text-center text-muted-foreground font-medium uppercase tracking-widest flex items-center justify-center gap-1.5"><ShieldCheck className="h-3 w-3" /> Secure Payment Guaranteed</p>
                    </form>
                  </CardContent>
                </Card>

                {/* Help Card */}
                <Card className="rounded-[2rem] border-0 bg-white shadow-sm p-6 flex items-center gap-4">
                  <div className="bg-emerald-100 p-3 rounded-2xl text-emerald-700">
                    <Info className="h-6 w-6" />
                  </div>
                  <div>
                    <p className="text-sm font-bold">Need Assistance?</p>
                    <p className="text-xs text-muted-foreground">Our support team is available 24/7 at support@tripease.com</p>
                  </div>
                </Card>
              </aside>
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
}

import { useState, useEffect, useCallback } from "react";
import { Search, MapPin, Star, SlidersHorizontal, Loader, Calendar, Users, Filter, X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import Layout from "@/components/layout/Layout";
import { hotelsService, Hotel } from "@/services/hotels";
import { HotelCard } from "@/components/cards/HotelCard";
import { toast } from "sonner";
import { useDebounce } from "@/hooks/use-debounce";

const AMENITIES = ["WiFi", "Swimming Pool", "Spa", "Gym", "Restaurant", "Beach Access", "Parking", "AC"];
const REGIONS = ["Greater Accra", "Ashanti", "Central", "Western", "Northern", "Eastern", "Volta", "Bono", "Upper East", "Upper West"];

const Hotels = () => {
  const [searchQuery, setSearchQuery] = useState("");
  const [region, setRegion] = useState("all");
  const [starRating, setStarRating] = useState("all");
  const [sortBy, setSortBy] = useState("default");
  const [hotels, setHotels] = useState<Hotel[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [minPrice, setMinPrice] = useState("");
  const [maxPrice, setMaxPrice] = useState("");
  const [selectedAmenities, setSelectedAmenities] = useState<string[]>([]);
  const [showFilters, setShowFilters] = useState(false);

  const debouncedSearch = useDebounce(searchQuery, 500);

  const loadHotels = useCallback(async () => {
    setIsLoading(true);
    try {
      const data = await hotelsService.searchHotels({
        location: debouncedSearch,
        region: region === "all" ? undefined : region,
        minPrice: minPrice ? parseFloat(minPrice) : undefined,
        maxPrice: maxPrice ? parseFloat(maxPrice) : undefined,
        rating: starRating === "all" ? undefined : starRating,
        amenities: selectedAmenities.length > 0 ? selectedAmenities : undefined,
        sortBy: sortBy === "default" ? undefined : sortBy,
        limit: 100,
      });
      setHotels(data);
    } catch (error: any) {
      toast.error("Failed to load hotels");
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  }, [debouncedSearch, region, minPrice, maxPrice, starRating, selectedAmenities, sortBy]);

  useEffect(() => {
    loadHotels();
  }, [loadHotels]);

  const toggleAmenity = (amenity: string) => {
    setSelectedAmenities(prev =>
      prev.includes(amenity) ? prev.filter(a => a !== amenity) : [...prev, amenity]
    );
  };

  const clearFilters = () => {
    setSearchQuery("");
    setRegion("all");
    setStarRating("all");
    setMinPrice("");
    setMaxPrice("");
    setSelectedAmenities([]);
    setSortBy("default");
  };

  return (
    <Layout>
      <section className="bg-gradient-to-br from-emerald-900 via-teal-800 to-cyan-900 py-16 text-white overflow-hidden relative">
        <div className="absolute inset-0 opacity-10 bg-[url('https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=1200')] bg-cover bg-center" />
        <div className="container relative">
          <Badge className="mb-4 bg-emerald-500/20 text-emerald-200 border-emerald-500/30">Luxury Accommodations</Badge>
          <h1 className="mb-4 font-display text-4xl font-extrabold md:text-6xl tracking-tight">Stay in the Heart of <br /><span className="text-emerald-400 font-cursive italic">Ghana</span></h1>
          <p className="mb-8 text-white/80 text-lg max-w-xl">From coastal resorts to urban luxury, find your sanctuary away from home with our curated hotel collection.</p>

          <div className="flex flex-col gap-3 rounded-2xl bg-white/10 backdrop-blur-md p-4 border border-white/20 shadow-2xl md:flex-row max-w-4xl">
            <div className="flex flex-[2] items-center gap-3 rounded-xl bg-white/10 px-4 py-2 border border-white/10 group focus-within:bg-white/20 transition-all">
              <Search className="h-5 w-5 text-emerald-400" />
              <Input
                placeholder="Where are you going?"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="border-0 bg-transparent shadow-none focus-visible:ring-0 text-white placeholder:text-white/50 text-base"
              />
            </div>
            <div className="flex flex-1 items-center gap-3 rounded-xl bg-white/10 px-4 py-2 border border-white/10 group focus-within:bg-white/20 transition-all">
              <MapPin className="h-5 w-5 text-emerald-400" />
              <Select value={region} onValueChange={setRegion}>
                <SelectTrigger className="border-0 bg-transparent shadow-none focus:ring-0 text-white p-0 h-auto">
                  <SelectValue placeholder="All Regions" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Regions</SelectItem>
                  {REGIONS.map(r => <SelectItem key={r} value={r}>{r}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <Button size="lg" className="rounded-xl bg-emerald-500 hover:bg-emerald-600 text-white px-8 h-12">Search</Button>
          </div>
        </div>
      </section>

      <section className="py-12 bg-muted/30 min-h-screen">
        <div className="container">
          <div className="flex flex-col lg:flex-row gap-8">
            {/* Sidebar Filters */}
            <aside className="w-full lg:w-72 space-y-8 bg-white p-6 rounded-2xl shadow-sm border h-fit sticky top-24">
              <div className="flex items-center justify-between">
                <h3 className="font-bold flex items-center gap-2 tracking-tight text-lg"><Filter className="h-4 w-4 text-emerald-600" /> Filter Stays</h3>
                <button onClick={clearFilters} className="text-xs text-muted-foreground hover:text-emerald-600 font-medium">Clear All</button>
              </div>

              <div className="space-y-4">
                <label className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Price Range (GH₵)</label>
                <div className="flex items-center gap-3">
                  <Input type="number" placeholder="Min" value={minPrice} onChange={(e) => setMinPrice(e.target.value)} className="rounded-xl border-muted bg-muted/30 focus-visible:ring-emerald-500" />
                  <span className="text-muted-foreground font-light">—</span>
                  <Input type="number" placeholder="Max" value={maxPrice} onChange={(e) => setMaxPrice(e.target.value)} className="rounded-xl border-muted bg-muted/30 focus-visible:ring-emerald-500" />
                </div>
              </div>

              <div className="space-y-4">
                <label className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Rating</label>
                <Select value={starRating} onValueChange={setStarRating}>
                  <SelectTrigger className="rounded-xl border-muted bg-muted/30 focus:ring-emerald-500 shadow-none"><SelectValue placeholder="Select Rating" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Ratings</SelectItem>
                    <SelectItem value="4.5">4.5+ (Exceptional)</SelectItem>
                    <SelectItem value="4.0">4.0+ (Great)</SelectItem>
                    <SelectItem value="3.5">3.5+ (Good)</SelectItem>
                    <SelectItem value="3.0">3.0+ (Average)</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-4">
                <label className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Amenities</label>
                <div className="grid grid-cols-1 gap-2">
                  {AMENITIES.map(amenity => (
                    <label key={amenity} className="flex items-center gap-3 cursor-pointer group">
                      <div
                        className={`w-5 h-5 rounded-md border-2 transition-all flex items-center justify-center ${selectedAmenities.includes(amenity) ? 'bg-emerald-500 border-emerald-500' : 'border-muted group-hover:border-emerald-300'}`}
                        onClick={(e) => { e.preventDefault(); toggleAmenity(amenity); }}
                      >
                        {selectedAmenities.includes(amenity) && <X className="h-3 w-3 text-white" />}
                      </div>
                      <span className={`text-sm ${selectedAmenities.includes(amenity) ? 'text-foreground font-medium' : 'text-muted-foreground'}`}>{amenity}</span>
                    </label>
                  ))}
                </div>
              </div>
            </aside>

            {/* Content Area */}
            <div className="flex-1 space-y-6">
              <div className="flex items-center justify-between pb-4 border-b">
                <div>
                  <h2 className="text-xl font-bold tracking-tight">Available Hotels</h2>
                  <p className="text-sm text-muted-foreground">Found {hotels.length} places for your stay</p>
                </div>
                <div className="flex items-center gap-2">
                  <span className="text-sm text-muted-foreground hidden sm:inline">Sort By:</span>
                  <Select value={sortBy} onValueChange={setSortBy}>
                    <SelectTrigger className="w-[180px] rounded-full bg-muted/50 border-0 focus:ring-emerald-500"><SelectValue placeholder="Sort Default" /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="default">Newest Added</SelectItem>
                      <SelectItem value="price-asc">Price: Low to High</SelectItem>
                      <SelectItem value="price-desc">Price: High to Low</SelectItem>
                      <SelectItem value="rating">Top Rated</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {isLoading ? (
                <div className="grid gap-6 md:grid-cols-2">
                  {[1, 2, 3, 4].map(i => (
                    <div key={i} className="h-[400px] rounded-2xl bg-muted animate-pulse border border-muted/50" />
                  ))}
                </div>
              ) : hotels.length === 0 ? (
                <div className="flex flex-col items-center justify-center rounded-3xl border border-dashed border-muted-foreground/30 bg-card py-32">
                  <div className="bg-muted p-6 rounded-full mb-6">
                    <Search className="h-12 w-12 text-muted-foreground/50" />
                  </div>
                  <h3 className="text-2xl font-bold">No stays found</h3>
                  <p className="text-muted-foreground mt-2 max-w-xs text-center">We couldn't find any hotels matching your current filters. Try relaxing your criteria.</p>
                  <Button variant="outline" className="mt-8 rounded-full px-8" onClick={clearFilters}>Reset All Filters</Button>
                </div>
              ) : (
                <div className="grid gap-8 md:grid-cols-2">
                  {hotels.map((hotel) => (
                    <HotelCard key={hotel.id} hotel={hotel} />
                  ))}
                </div>
              )}

              {!isLoading && hotels.length > 0 && (
                <div className="flex justify-center pt-8">
                  <Button variant="outline" className="rounded-full px-12 border-emerald-500/30 text-emerald-700 hover:bg-emerald-50">Show More Stays</Button>
                </div>
              )}
            </div>
          </div>
        </div>
      </section>
    </Layout>
  );
};

export default Hotels;

import { Link, useNavigate } from "react-router-dom";
import { Mail, Lock, User, Eye, EyeOff, Loader } from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import Layout from "@/components/layout/Layout";
import { useAuth } from "@/context/AuthContext";
import { toast } from "sonner";

const Login = () => {
  const navigate = useNavigate();
  const { login, verifyMFA, isLoading } = useAuth();
  const [showPw, setShowPw] = useState(false);
  const [mfaRequired, setMfaRequired] = useState(false);
  const [mfaCode, setMfaCode] = useState("");
  const [mfaEmail, setMfaEmail] = useState("");
  const [formData, setFormData] = useState({
    email: "",
    password: "",
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const result = await login(formData.email, formData.password);
      
      if (result.mfaRequired) {
        setMfaRequired(true);
        setMfaEmail(result.email || formData.email);
        toast.info("Verification code sent to your email");
        return;
      }

      if (result.user) {
        toast.success("Logged in successfully!");
        if (result.user.requires_password_change) {
          navigate("/change-password-required");
        } else {
          navigate("/dashboard");
        }
      }
    } catch (error: any) {
      toast.error(error.message || "Login failed");
    }
  };

  const handleMfaSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const user = await verifyMFA(mfaEmail, mfaCode);
      toast.success("Verified successfully!");
      if (user.requires_password_change) {
        navigate("/change-password-required");
      } else {
        navigate("/dashboard");
      }
    } catch (error: any) {
      toast.error(error.message || "Invalid verification code");
    }
  };

  return (
    <Layout>
      <div className="flex min-h-[80vh] items-center justify-center py-12">
        <div className="mx-auto w-full max-w-md animate-fade-in text-center px-4">
          <div className="rounded-2xl border border-border bg-card p-8 shadow-primary-sm">
            {!mfaRequired ? (
              <>
                <div className="mb-6 text-center">
                  <h1 className="font-display text-2xl font-bold">Welcome Back</h1>
                  <p className="text-sm text-muted-foreground">Sign in to your TripEase account</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                  <div className="text-left">
                    <label className="mb-1 block text-sm font-medium">Email</label>
                    <div className="relative">
                      <Mail className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                      <Input
                        type="email"
                        name="email"
                        placeholder="you@example.com"
                        className="pl-10"
                        value={formData.email}
                        onChange={handleChange}
                        required
                      />
                    </div>
                  </div>
                  <div className="text-left">
                    <label className="mb-1 block text-sm font-medium">Password</label>
                    <div className="relative">
                      <Lock className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                      <Input
                        type={showPw ? "text" : "password"}
                        name="password"
                        placeholder="••••••••"
                        className="pl-10 pr-10"
                        value={formData.password}
                        onChange={handleChange}
                        required
                      />
                      <button
                        type="button"
                        onClick={() => setShowPw(!showPw)}
                        className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground"
                      >
                        {showPw ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                      </button>
                    </div>
                  </div>
                  <div className="flex justify-end">
                    <Link to="/forgot-password" className="text-sm text-primary hover:underline">
                      Forgot password?
                    </Link>
                  </div>
                  <Button className="w-full" size="lg" disabled={isLoading}>
                    {isLoading && <Loader className="mr-2 h-4 w-4 animate-spin" />}
                    Sign In
                  </Button>
                </form>

                <div className="my-6 flex items-center gap-3">
                  <div className="h-px flex-1 bg-border" />
                  <span className="text-xs text-muted-foreground">OR</span>
                  <div className="h-px flex-1 bg-border" />
                </div>

                <Button variant="outline" className="w-full gap-2" size="lg">
                  <svg className="h-4 w-4" viewBox="0 0 24 24">
                    <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" />
                    <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
                    <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
                    <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
                  </svg>
                  Sign in with Google
                </Button>

                <p className="mt-6 text-center text-sm text-muted-foreground">
                  Don't have an account?{" "}
                  <Link to="/register" className="text-primary hover:underline">Create one</Link>
                </p>
              </>
            ) : (
              <div className="animate-in fade-in zoom-in duration-300">
                <div className="mb-6 text-center">
                  <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-primary/10 text-primary">
                    <User className="h-6 w-6" />
                  </div>
                  <h1 className="font-display text-2xl font-bold">Shield Active</h1>
                  <p className="text-sm text-muted-foreground px-4">
                    Enter the verification code sent to <br/>
                    <span className="font-medium text-foreground">{mfaEmail}</span>
                  </p>
                </div>

                <form onSubmit={handleMfaSubmit} className="space-y-6">
                  <div>
                    <Input
                      type="text"
                      placeholder="Enter 6-digit code"
                      className="text-center text-2xl tracking-[0.5em] font-mono h-14"
                      maxLength={6}
                      value={mfaCode}
                      onChange={(e) => setMfaCode(e.target.value.replace(/\D/g, ""))}
                      required
                      autoFocus
                    />
                  </div>
                  
                  <div className="space-y-3">
                    <Button className="w-full h-12 text-base" disabled={isLoading || mfaCode.length !== 6}>
                      {isLoading && <Loader className="mr-2 h-4 w-4 animate-spin" />}
                      Verify & Login
                    </Button>
                    <Button 
                      type="button" 
                      variant="ghost" 
                      className="w-full" 
                      onClick={() => setMfaRequired(false)}
                      disabled={isLoading}
                    >
                      Back to Login
                    </Button>
                  </div>
                </form>

                <p className="mt-8 text-xs text-muted-foreground">
                  Didn't receive a code? Check your spam folder or contact support.
                </p>
              </div>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default Login;

import { Link, useNavigate } from "react-router-dom";
import { Mail, Lock, User, Eye, EyeOff, Phone, Loader } from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import Layout from "@/components/layout/Layout";
import { useAuth } from "@/context/AuthContext";
import { toast } from "sonner";

const Register = () => {
  const navigate = useNavigate();
  const { register, isLoading } = useAuth();
  const [showPw, setShowPw] = useState(false);
  const [formData, setFormData] = useState({
    firstName: "",
    lastName: "",
    email: "",
    phone: "",
    password: "",
    role: "traveller",
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.firstName || !formData.lastName || !formData.email || !formData.password) {
      toast.error("Please fill in all required fields");
      return;
    }

    if (formData.password.length < 6) {
      toast.error("Password must be at least 6 characters");
      return;
    }

    try {
      const fullName = `${formData.firstName} ${formData.lastName}`;
      await register(formData.email, formData.password, fullName, formData.phone || undefined);
      toast.success("Account created successfully!");
      navigate("/dashboard");
    } catch (error: any) {
      toast.error(error.message || "Registration failed");
    }
  };

  return (
    <Layout>
      <div className="flex min-h-[80vh] items-center justify-center py-12">
        <div className="mx-auto w-full max-w-md animate-fade-in">
          <div className="rounded-2xl border border-border bg-card p-8 shadow-primary-sm">
            <div className="mb-6 text-center">
              <h1 className="font-display text-2xl font-bold">Create Account</h1>
              <p className="text-sm text-muted-foreground">Join TripEase Ghana today</p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="mb-1 block text-sm font-medium">First Name</label>
                  <Input
                    name="firstName"
                    placeholder="Kwame"
                    value={formData.firstName}
                    onChange={handleChange}
                    required
                  />
                </div>
                <div>
                  <label className="mb-1 block text-sm font-medium">Last Name</label>
                  <Input
                    name="lastName"
                    placeholder="Mensah"
                    value={formData.lastName}
                    onChange={handleChange}
                    required
                  />
                </div>
              </div>
              <div>
                <label className="mb-1 block text-sm font-medium">Email</label>
                <div className="relative">
                  <Mail className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    type="email"
                    name="email"
                    placeholder="you@example.com"
                    className="pl-10"
                    value={formData.email}
                    onChange={handleChange}
                    required
                  />
                </div>
              </div>
              <div>
                <label className="mb-1 block text-sm font-medium">Phone</label>
                <div className="relative">
                  <Phone className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    type="tel"
                    name="phone"
                    placeholder="+233 XX XXX XXXX"
                    className="pl-10"
                    value={formData.phone}
                    onChange={handleChange}
                  />
                </div>
              </div>
              <div>
                <label className="mb-1 block text-sm font-medium">Account Type</label>
                <Select value={formData.role} onValueChange={(value) => setFormData({ ...formData, role: value })}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select role" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="traveller">Traveller</SelectItem>
                    <SelectItem value="provider">Service Provider</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <label className="mb-1 block text-sm font-medium">Password</label>
                <div className="relative">
                  <Lock className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                  <Input
                    type={showPw ? "text" : "password"}
                    name="password"
                    placeholder="••••••••"
                    className="pl-10 pr-10"
                    value={formData.password}
                    onChange={handleChange}
                    required
                  />
                  <button type="button" onClick={() => setShowPw(!showPw)} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground">
                    {showPw ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </button>
                </div>
              </div>
