                                <Button className="w-full bg-emerald-500 hover:bg-emerald-400 text-white border-0 rounded-xl">
                                    Chat with an Expert
                                </Button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <ShareDestination 
