                    <div className="py-20 flex flex-col items-center gap-4 text-muted-foreground">
                        <Loader className="h-10 w-10 animate-spin text-primary" />
                        <p>Discovering amazing places...</p>
                    </div>
                ) : (
                    <>
                        <p className="text-sm font-medium text-slate-500 mb-6">{filtered.length} destination{filtered.length !== 1 ? "s" : ""} found</p>

                        <div className="grid gap-8 md:grid-cols-2 lg:grid-cols-3">
                            {filtered.map((dest) => (
                                <div key={dest.id} className="group overflow-hidden rounded-[2rem] border border-slate-100 bg-white shadow-xl shadow-slate-200/50 hover:shadow-2xl hover:shadow-primary/10 transition-all duration-500 ease-out flex flex-col">
                                    <div className="relative overflow-hidden h-64">
                                        <img
                                            src={dest.image_url}
                                            alt={dest.name}
                                            className="h-full w-full object-cover transition-transform duration-700 group-hover:scale-110"
                                        />
                                        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent opacity-60 group-hover:opacity-80 transition-opacity" />
                                        
                                        <div className="absolute top-4 left-4">
                                            <Badge className={`rounded-xl px-3 py-1 text-[10px] font-bold uppercase tracking-wider ${categoryColors[dest.category] || "bg-white/90 text-slate-800 shadow-sm border-none backdrop-blur-sm"} border-none`}>
                                                {dest.category}
                                            </Badge>
                                        </div>
                                        
                                        <div className="absolute bottom-4 left-4 right-4 flex items-center justify-between text-white">
                                            <div className="flex items-center gap-1.5">
                                                <div className="h-6 w-6 rounded-lg bg-white/20 backdrop-blur-md flex items-center justify-center">
                                                    <MapPin className="h-3.5 w-3.5" />
                                                </div>
                                                <span className="text-xs font-bold tracking-tight">{dest.region}</span>
                                            </div>
                                            <div className="flex items-center gap-1 bg-white/90 text-primary px-2 py-1 rounded-lg shadow-sm">
                                                <Star className="h-3 w-3 fill-primary" />
                                                <span className="text-[11px] font-bold">{dest.rating || "New"}</span>
                                            </div>
                                        </div>
                                    </div>
                                    
                                    <div className="p-6 flex-1 flex flex-col">
                                        <h3 className="font-display text-xl font-extrabold mb-2 text-slate-800 group-hover:text-primary transition-colors leading-tight">
                                            {dest.name}
                                        </h3>
                                        <p className="text-sm text-slate-500 line-clamp-2 mb-6 leading-relaxed flex-1">
                                            {dest.description}
                                        </p>
                                        
                                        <div className="flex items-center justify-between pt-4 border-t border-slate-50 mt-auto">
                                            <Button
                                                asChild
                                                variant="ghost"
                                                className="text-primary font-bold text-xs gap-1 group/link p-0 hover:bg-transparent"
                                            >
                                                <Link to={`/destinations/${dest.id}`}>
                                                    View Details 
                                                    <ArrowRight className="h-3.5 w-3.5 transition-transform group-hover/link:translate-x-1" />
                                                </Link>
                                            </Button>
                                            
                                            <Button
                                                size="sm"
                                                className="rounded-xl h-9 px-4 text-[11px] font-bold bg-slate-900 border-none hover:bg-primary transition-all shadow-md group-hover:shadow-primary/20"
                                                onClick={() => navigate(`/trips/new?destination=${encodeURIComponent(dest.name)}`)}
                                            >
                                                Book Now
                                            </Button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>

                        {filtered.length === 0 && (
                            <div className="py-24 text-center rounded-[3rem] bg-slate-50 border-2 border-dashed border-slate-200">
                                <div className="h-20 w-20 rounded-[2rem] bg-slate-100 flex items-center justify-center mx-auto mb-6 text-slate-300">
                                    <MapPin className="h-10 w-10" />
                                </div>
                                <h3 className="text-xl font-bold text-slate-800 mb-2">Hidden Gems Only?</h3>
                                <p className="text-slate-500 max-w-xs mx-auto">We couldn't find any destinations matching your search. Try broadening your criteria!</p>
                                <Button 
                                    variant="link" 
                                    className="mt-4 text-primary font-bold"
                                    onClick={() => { setSearch(""); setSelectedCategory("all"); setSelectedRegion("All Regions"); }}
                                >
                                    Clear all filters
                                </Button>
                            </div>
                        )}
                    </>
                )}
            </div>
        </Layout>
    );
}

const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:3001/api';

export interface ApiResponse<T> {
  success: boolean;
  message?: string;
  data?: T;
}

class ApiClient {
  private csrfToken: string | null = null;

  private getToken(): string | null {
    return localStorage.getItem('authToken');
  }

  private async fetchCsrfToken(force = false): Promise<string> {
    if (this.csrfToken && !force) return this.csrfToken;
    try {
      const response = await fetch(`${API_URL}/csrf-token`, {
        method: 'GET',
        credentials: 'include', // Ensure cookies are sent to generate the right token
      });
      if (!response.ok) throw new Error('CSRF response not OK');
      const data = await response.json();
      this.csrfToken = data.csrfToken;
      return this.csrfToken!;
    } catch (e) {
      console.error('Failed to fetch CSRF token', e);
      return '';
    }
  }

  private async getHeaders(isMutating = false): Promise<Record<string, string>> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };

    const token = this.getToken();
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    if (isMutating) {
      const csrf = await this.fetchCsrfToken();
      if (csrf) headers['x-csrf-token'] = csrf;
    }

    return headers;
  }

  async get<T>(endpoint: string, params?: Record<string, any>): Promise<ApiResponse<T>> {
    let url = `${API_URL}${endpoint}`;
    if (params) {
      const qs = new URLSearchParams();
      Object.entries(params).forEach(([key, value]) => {
        if (value !== undefined && value !== null && value !== 'all') {
          qs.append(key, String(value));
        }
      });
      const qsStr = qs.toString();
      if (qsStr) url += `?${qsStr}`;
    }

    const options: RequestInit = {
      method: 'GET',
      headers: await this.getHeaders(),
      credentials: 'include',
    };
    const response = await fetch(url, options);

    return this.handleResponse<T>(response, { ...options, url });
  }

  async post<T>(endpoint: string, data?: any): Promise<ApiResponse<T>> {
    const url = `${API_URL}${endpoint}`;
    const options: RequestInit = {
      method: 'POST',
      headers: await this.getHeaders(true),
      body: data ? JSON.stringify(data) : undefined,
      credentials: 'include',
    };
    const response = await fetch(url, options);

    return this.handleResponse<T>(response, { ...options, url });
  }

  async put<T>(endpoint: string, data?: any): Promise<ApiResponse<T>> {
    const url = `${API_URL}${endpoint}`;
    const options: RequestInit = {
      method: 'PUT',
      headers: await this.getHeaders(true),
      body: data ? JSON.stringify(data) : undefined,
      credentials: 'include',
    };
    const response = await fetch(url, options);

    return this.handleResponse<T>(response, { ...options, url });
  }

  async delete<T>(endpoint: string): Promise<ApiResponse<T>> {
    const url = `${API_URL}${endpoint}`;
    const options: RequestInit = {
      method: 'DELETE',
      headers: await this.getHeaders(true),
      credentials: 'include',
    };
    const response = await fetch(url, options);

    return this.handleResponse<T>(response, { ...options, url });
  }

  private isRefreshing = false;
  private refreshSubscribers: ((newToken: string) => void)[] = [];

  private onTokenRefreshed(newToken: string) {
    this.refreshSubscribers.forEach(cb => cb(newToken));
    this.refreshSubscribers = [];
  }

  private async handleResponse<T>(response: Response, requestOptions?: any): Promise<ApiResponse<T>> {
    const contentType = response.headers.get('content-type');
    let data: any;

    if (contentType?.includes('application/json')) {
      data = await response.json();
    } else {
      data = await response.text();
    }

    if (!response.ok) {
      // If it's a CSRF error, try to fetch a new token and retry once
      const isCsrfError = response.status === 403 && data?.message?.toLowerCase().includes('csrf');
      const isAuthError = response.status === 401;

      if (isCsrfError && requestOptions && !requestOptions._isRetry) {
        console.warn('CSRF Token invalid, retrying...');
        const newToken = await this.fetchCsrfToken(true);
        if (newToken) {
          const newHeaders = { ...requestOptions.headers, 'x-csrf-token': newToken };
          const retryResponse = await fetch(requestOptions.url, {
            ...requestOptions,
            headers: newHeaders,
            _isRetry: true
          } as any);
          return this.handleResponse<T>(retryResponse);
        }
      }

      if (isAuthError && requestOptions && !requestOptions._isRetry) {
        if (this.isRefreshing) {
          console.log('Refresh already in progress, queuing request...');
          return new Promise<ApiResponse<T>>((resolve) => {
            this.refreshSubscribers.push(async (newToken: string) => {
              const newHeaders = { ...requestOptions.headers, 'Authorization': `Bearer ${newToken}` };
              const retryResponse = await fetch(requestOptions.url, {
                ...requestOptions,
                headers: newHeaders,
                _isRetry: true
              } as any);
              resolve(this.handleResponse<T>(retryResponse));
            });
          });
        }

        const refreshToken = localStorage.getItem('refreshToken');
        if (refreshToken) {
          this.isRefreshing = true;
          console.warn('Auth Token expired, attempting refresh...');
          try {
            const csrfToken = await this.fetchCsrfToken();
            const refreshResponse = await fetch(`${API_URL}/auth/refresh-token`, {
              method: 'POST',
              headers: {
                'Content-Type': 'application/json',
                'x-csrf-token': csrfToken
              },
              body: JSON.stringify({ refreshToken }),
              credentials: 'include',
            });

            if (refreshResponse.ok) {
              const refreshData = await refreshResponse.json();
              if (refreshData.success && refreshData.data?.token) {
                const newToken = refreshData.data.token;
                const newRefreshToken = refreshData.data.refreshToken;

                localStorage.setItem('authToken', newToken);
                if (newRefreshToken) {
                  localStorage.setItem('refreshToken', newRefreshToken);
                }

                this.isRefreshing = false;
                this.onTokenRefreshed(newToken);

                const newHeaders = { ...requestOptions.headers, 'Authorization': `Bearer ${newToken}` };
                const retryResponse = await fetch(requestOptions.url, {
                  ...requestOptions,
                  headers: newHeaders,
                  _isRetry: true
                } as any);
                return this.handleResponse<T>(retryResponse);
              }
            }
          } catch (e) {
            console.error('Refresh token attempt failed', e);
          } finally {
            this.isRefreshing = false;
          }
        }
        // If we get here, refresh failed or was not possible
        localStorage.removeItem('authToken');
      }

      const error = new Error(data?.message || 'An error occurred');
      (error as any).statusCode = response.status;
      throw error;
    }

    return data;
  }
}

export const apiClient = new ApiClient();

import { apiClient, ApiResponse } from './api';

export interface User {
  id: string;
  email: string;
  full_name: string;
  phone?: string;
  avatar_url?: string;
  bio?: string;
  role: 'user' | 'admin' | 'provider';
  preferences?: any;
  created_at?: string;
  requires_password_change?: boolean;
  two_factor_enabled?: boolean;
}

export interface AuthResponse {
  user?: User;
  token?: string;
  refreshToken?: string;
  mfaRequired?: boolean;
  email?: string;
}

export const authService = {
  async register(email: string, password: string, fullName: string, phone?: string): Promise<AuthResponse> {
    const response = await apiClient.post<AuthResponse>('/auth/register', {
      email,
      password,
      fullName,
      phone,
    });
    const { user, token, refreshToken } = response.data!;
    this.setToken(token);
    this.setRefreshToken(refreshToken);
    return response.data!;
  },

  async login(email: string, password: string): Promise<AuthResponse> {
    const response = await apiClient.post<AuthResponse>('/auth/login', {
      email,
      password,
    });
    const { token, refreshToken, mfaRequired } = response.data!;
    if (!mfaRequired && token && refreshToken) {
      this.setToken(token);
      this.setRefreshToken(refreshToken);
    }
    return response.data!;
  },

  async adminLogin(email: string, password: string): Promise<AuthResponse> {
    const response = await apiClient.post<AuthResponse>('/auth/admin-login', {
      email,
      password,
    });
    const { token, refreshToken, mfaRequired } = response.data!;
    if (!mfaRequired && token && refreshToken) {
      this.setToken(token);
      this.setRefreshToken(refreshToken);
    }
    return response.data!;
  },

  async verifyMFA(email: string, code: string): Promise<AuthResponse> {
    const response = await apiClient.post<AuthResponse>('/auth/verify-mfa', {
      email,
      code,
    });
    const { token, refreshToken } = response.data!;
    if (token && refreshToken) {
      this.setToken(token);
      this.setRefreshToken(refreshToken);
    }
    return response.data!;
  },

  async getProfile(): Promise<User> {
    const response = await apiClient.get<User>('/auth/profile');
    return response.data!;
  },

  async updateProfile(fullName?: string, phone?: string, bio?: string, avatarUrl?: string): Promise<User> {
    const response = await apiClient.put<User>('/auth/profile', {
      fullName,
      phone,
      bio,
      avatarUrl,
    });
    return response.data!;
  },

  async changePassword(currentPassword: string, newPassword: string): Promise<void> {
    await apiClient.put('/auth/change-password', {
      currentPassword,
      newPassword,
    });
  },

  async forgotPassword(email: string): Promise<void> {
    await apiClient.post('/auth/forgot-password', { email });
  },

  async resetPassword(token: string, password: string): Promise<void> {
    await apiClient.post('/auth/reset-password', { token, password });
  },

  async updatePreferences(preferences: any): Promise<any> {
    const response = await apiClient.put<any>('/auth/preferences', {
      preferences,
    });
    return response.data!;
  },

  async toggleMFA(enabled: boolean): Promise<any> {
    const response = await apiClient.put<any>('/auth/toggle-mfa', {
      enabled,
    });
    return response.data!;
  },

  setToken(token: string): void {
    localStorage.setItem('authToken', token);
  },

  getToken(): string | null {
    return localStorage.getItem('authToken');
  },

  setRefreshToken(token: string): void {
    localStorage.setItem('refreshToken', token);
  },

  getRefreshToken(): string | null {
    return localStorage.getItem('refreshToken');
  },

  clearToken(): void {
    localStorage.removeItem('authToken');
    localStorage.removeItem('refreshToken');
  },

  isAuthenticated(): boolean {
    return !!this.getToken();
  },
};

import { apiClient } from './api';

export interface Attraction {
    id: string;
    destination_id: string;
    destination_name?: string;
    name: string;
    category: string;
    description: string;
    full_description?: string;
    image_url: string;
    gallery?: string[];
    travel_tips?: string[];
    activities?: string[];
    best_time?: string;
    entrance_fee: string;
    opening_hours: string;
}

export interface Destination {
    id: string;
    name: string;
    description: string;
    full_description?: string;
    region: string;
    category: string;
    image_url: string;
    gallery?: string[];
    travel_tips?: string[];
    activities?: string[];
    best_time?: string;
    rating: number;
    attractions?: Attraction[];
}

export const destinationsService = {
    async getDestinations(params?: { category?: string; region?: string; search?: string }): Promise<Destination[]> {
        const response = await apiClient.get<{ success: boolean; data: Destination[] }>('/destinations', { params });
        return response.data?.data || [];
    },

    async getDestinationById(id: string): Promise<Destination> {
        const response = await apiClient.get<{ success: boolean; data: Destination }>(`/destinations/${id}`);
        return response.data?.data!;
    },

    async getAttractionById(id: string): Promise<Attraction> {
        const response = await apiClient.get<{ success: boolean; data: Attraction }>(`/destinations/attractions/${id}`);
        return response.data?.data!;
    },

    async searchAttractions(params?: { search?: string; category?: string }): Promise<Attraction[]> {
        const response = await apiClient.get<{ success: boolean; data: Attraction[] }>('/destinations/attractions/search', { params });
        return response.data?.data || [];
    }
};

